const cheerio = require('cheerio');
const html = $input.item.json.data || $input.item.json;
const $ = cheerio.load(html);

const jobs = [];

// Sélecteurs LinkedIn multiples (robustesse)
const selectors = [
  '.base-card',
  '.job-search-card',
  '.jobs-search__results-list li',
  '[data-job-id]',
  '.scaffold-layout__list-item'
];

let jobElements = $();
for (const selector of selectors) {
  jobElements = $(selector);
  if (jobElements.length > 0) {
    console.log(`✅ Sélecteur trouvé: ${selector} (${jobElements.length} jobs)`);
    break;
  }
}

if (jobElements.length === 0) {
  console.log('⚠️ Aucun job trouvé avec sélecteurs classiques');
  console.log('HTML preview:', html.substring(0, 500));
}

jobElements.each((i, el) => {
  const $el = $(el);

  // Extraction multi-sélecteurs
  const title = (
    $el.find('.base-search-card__title').text() ||
    $el.find('h3').text() ||
    $el.find('[class*="title"]').text() ||
    ''
  ).trim();

  const company = (
    $el.find('.base-search-card__subtitle').text() ||
    $el.find('h4').text() ||
    $el.find('[class*="company"]').text() ||
    ''
  ).trim();

  const location = (
    $el.find('.job-search-card__location').text() ||
    $el.find('[class*="location"]').text() ||
    ''
  ).trim();

  const description = (
    $el.find('.base-search-card__snippet').text() ||
    $el.find('[class*="snippet"]').text() ||
    ''
  ).trim();

  const url = (
    $el.find('a.base-card__full-link').attr('href') ||
    $el.find('a[href*="/jobs/view/"]').attr('href') ||
    $el.find('a').first().attr('href') ||
    ''
  );

  const jobId = (
    $el.attr('data-job-id') ||
    url.match(/\/jobs\/view\/(\d+)/)?.[1] ||
    null
  );

  const postedTime = (
    $el.find('time').attr('datetime') ||
    $el.find('[class*="time"]').text() ||
    null
  );

  // Validation
  if (title && (url || jobId)) {
    jobs.push({
      job_id: jobId,
      title: title,
      company: company || 'Non spécifié',
      location: location || 'Non spécifié',
      raw_description: description,
      url: url.startsWith('http') ? url : `https://www.linkedin.com${url}`,
      posted_time: postedTime,
      source: 'LinkedIn',
      scraping_source: 'linkedin_visual',
      scraping_method: 'scrapingbee',
      scraped_at: new Date().toISOString()
    });
  }
});

console.log(`✅ [LinkedIn Visual] Jobs extraits: ${jobs.length}`);

if (jobs.length === 0) {
  console.log('⚠️ Aucun job extrait - Vérifier sélecteurs ou HTML');
  return [{ json: { error: 'No jobs found', html_preview: html.substring(0, 1000) } }];
}

return jobs.map(j => ({ json: j }));

