const requiredFields = ['title', 'company', 'location', 'skills', 'experience_level', 'remote_type'];
const defaultJobStructure = {
  title: $('Function - Parse LinkedIn HTML').item.json.title,
  company: $('Function - Parse LinkedIn HTML').item.json.company,
  location: $('Function - Parse LinkedIn HTML').item.json.location,
  skills: [],
  experience_level: 'non_specifie',
  salary_estimate: null,
  remote_type: 'non_specifie',
  contract_type: 'CDI',
  technologies: [],
  description_enriched: $('Function - Parse LinkedIn HTML').item.json.raw_description,
  benefits: [],
  quality_score: 5,
  enriched: false
};

function validateAndCleanJSON(aiResponse, requiredFields, defaultStructure) {
  try {
    let parsedResponse;
    if (typeof aiResponse === 'object') {
      parsedResponse = aiResponse;
    } else if (typeof aiResponse === 'string') {
      const cleanResponse = aiResponse.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
      parsedResponse = JSON.parse(cleanResponse);
    }
    const missingFields = requiredFields.filter(f => !parsedResponse.hasOwnProperty(f));
    if (missingFields.length > 0) throw new Error(`Champs manquants: ${missingFields.join(', ')}`);
    return {
      json: {
        ...parsedResponse,
        ...($('Function - Parse LinkedIn HTML').item.json),
        enriched: true,
        validation_timestamp: new Date().toISOString()
      }
    };
  } catch (error) {
    return {
      json: {
        ...defaultStructure,
        ...($('Function - Parse LinkedIn HTML').item.json),
        enrichment_error: error.message
      }
    };
  }
}

const aiResponse = $input.item.json.ai_response;
return validateAndCleanJSON(aiResponse, requiredFields, defaultJobStructure);
